import { useRef } from "react";

const MAX_IMAGE_BYTES = 5 * 1024 * 1024;

export default function ProductMediaUpload({
  title,
  imageUrl,
  imageAlt,
  onImageChange,
  onError,
}) {
  const fileInputRef = useRef(null);

  const processFile = (file) => {
    if (!file.type.startsWith("image/")) {
      onError?.("Only image files are allowed");
      return;
    }
    if (file.size > MAX_IMAGE_BYTES) {
      onError?.("Image must be under 5MB");
      return;
    }

    const reader = new FileReader();
    reader.onload = () => {
      onImageChange({
        imageUrl: reader.result,
        imageAlt: file.name.replace(/\.[^.]+$/, "") || title,
      });
    };
    reader.onerror = () => onError?.("Could not read image");
    reader.readAsDataURL(file);
  };

  const handleFileInput = (event) => {
    const file = event.target.files?.[0];
    if (file) processFile(file);
    event.target.value = "";
  };

  return (
    <div className="product-media-upload">
    <s-stack direction="inline" gap="small" alignItems="start">
      {imageUrl ? (
        <s-box
          border="base"
          borderRadius="base"
          overflow="hidden"
          inlineSize="104px"
          blockSize="104px"
        >
          <s-image objectFit="cover" src={imageUrl} alt={imageAlt || title} />
        </s-box>
      ) : null}

      <s-clickable
        accessibilityLabel="Add image"
        border="base"
        borderRadius="base"
        borderStyle="dashed"
        background="subdued"
        inlineSize="104px"
        blockSize="104px"
        onClick={() => fileInputRef.current?.click()}
      >
        <s-stack alignItems="center" justifyContent="center" blockSize="100%">
          <s-text type="strong">+</s-text>
        </s-stack>
      </s-clickable>

      <input
        ref={fileInputRef}
        type="file"
        accept="image/*"
        hidden
        onChange={handleFileInput}
      />
    </s-stack>
    </div>
  );
}
