import { memo } from "react";
import { useNavigate } from "react-router-dom";
import ProductThumbnail from "./ProductThumbnail";
import {
  formatStatus,
  getInventorySummary,
  getStatusBadgeProps,
} from "../../utils/productDisplay";

const ProductRow = memo(function ProductRow({ product, productTypes = [] }) {
  const navigate = useNavigate();
  const checkboxId = `product-${product.id}`;
  const inventory = getInventorySummary(product.variants);
  const statusLabel = formatStatus(product.status);
  const title = product.title || "Untitled product";
  const openDetail = () =>
    navigate(`/products/${product.id}`, {
      state: { product, productTypes },
    });

  return (
    <s-table-row clickDelegate={checkboxId}>
      <s-table-cell>
        <s-stack direction="inline" gap="small" alignItems="center">
          <s-checkbox id={checkboxId} />
          <ProductThumbnail
            title={title}
            imageUrl={product.imageUrl}
            imageAlt={product.imageAlt}
          />
          <s-link
            href={`/products/${product.id}`}
            onClick={(event) => {
              event.preventDefault();
              openDetail();
            }}
          >
            {title}
          </s-link>
        </s-stack>
      </s-table-cell>
      <s-table-cell>
        <s-badge {...getStatusBadgeProps(product.status)}>{statusLabel}</s-badge>
      </s-table-cell>
      <s-table-cell>
        <s-text tone={inventory.isOutOfStock ? "critical" : undefined}>
          {inventory.label}
        </s-text>
      </s-table-cell>
      <s-table-cell>{product.productType || "—"}</s-table-cell>
      <s-table-cell>{product.vendor || "—"}</s-table-cell>
    </s-table-row>
  );
});

export default ProductRow;
