import { memo } from "react";
import { useNavigate } from "react-router-dom";
import ProductThumbnail from "./ProductThumbnail";
import {
  formatStatus,
  getInventorySummary,
  getStatusBadgeProps,
} from "../../utils/productDisplay";

const ProductListCard = memo(function ProductListCard({
  product,
  productTypes = [],
}) {
  const navigate = useNavigate();
  const checkboxId = `mobile-product-${product.id}`;
  const inventory = getInventorySummary(product.variants);
  const statusLabel = formatStatus(product.status);
  const title = product.title || "Untitled product";

  const openDetail = () =>
    navigate(`/products/${product.id}`, {
      state: { product, productTypes },
    });

  const stockText = `${inventory.totalStock} in stock`;
  const variantSuffix =
    inventory.variantCount > 1
      ? ` for ${inventory.variantCount} variants`
      : "";

  return (
    <article className="product-list-card">
      <div className="product-list-card__row">
        <s-checkbox id={checkboxId} />
        <button
          type="button"
          className="product-list-card__open"
          aria-label={`Open ${title}`}
          onClick={openDetail}
        >
          <ProductThumbnail
            title={title}
            imageUrl={product.imageUrl}
            imageAlt={product.imageAlt}
          />
        </button>
        <div className="product-list-card__main">
          <div className="product-list-card__heading">
            <s-link
              href={`/products/${product.id}`}
              onClick={(event) => {
                event.preventDefault();
                openDetail();
              }}
            >
              {title}
            </s-link>
            <s-badge {...getStatusBadgeProps(product.status)}>
              {statusLabel}
            </s-badge>
          </div>
          <p className="product-list-card__inventory">
            <span
              className={
                inventory.isOutOfStock
                  ? "product-list-card__stock--critical"
                  : undefined
              }
            >
              {stockText}
            </span>
            {variantSuffix ? (
              <span className="product-list-card__stock-muted">
                {variantSuffix}
              </span>
            ) : null}
          </p>
        </div>
      </div>
    </article>
  );
});

export default ProductListCard;
