import { PRODUCT_CATEGORY_TREE } from "../data/productCategories";

function isLeaf(node) {
  return Boolean(node.isLeaf) || !node.children?.length;
}

export function getCategoryTree() {
  return PRODUCT_CATEGORY_TREE;
}

export function getCategoryLevelItems(tree, breadcrumb) {
  let level = tree;
  for (const crumb of breadcrumb) {
    const node = level.find((item) => item.id === crumb.id);
    if (!node?.children?.length) return [];
    level = node.children;
  }
  return level;
}

export function flattenCategoryLeaves(tree, parentNames = []) {
  const leaves = [];

  for (const node of tree) {
    const path = [...parentNames, node.name];

    if (isLeaf(node)) {
      leaves.push({
        id: node.id,
        name: node.name,
        value: path.join(" > "),
      });
      continue;
    }

    if (node.children?.length) {
      leaves.push(...flattenCategoryLeaves(node.children, path));
    }
  }

  return leaves;
}

export function searchCategories(tree, query, extraTypes = []) {
  const q = query.trim().toLowerCase();
  let results = flattenCategoryLeaves(tree);

  for (const type of extraTypes) {
    const trimmed = String(type || "").trim();
    if (!trimmed) continue;
    if (results.some((item) => item.value === trimmed)) continue;
    results.push({ id: `db-${trimmed}`, name: trimmed, value: trimmed });
  }

  if (!q) return results;

  return results.filter(
    (item) =>
      item.name.toLowerCase().includes(q) ||
      item.value.toLowerCase().includes(q),
  );
}

export function getCategoryDisplayLabel(value) {
  const trimmed = String(value ?? "").trim();
  if (!trimmed) return "";
  const parts = trimmed.split(">").map((part) => part.trim()).filter(Boolean);
  return parts[parts.length - 1] ?? trimmed;
}

export function buildCategoryValue(_breadcrumb, leafName) {
  return String(leafName ?? "").trim();
}
