import { useCallback, useEffect, useMemo, useState } from "react";
import { useAppBridge } from "@shopify/app-bridge-react";
import { apiRequest } from "../../api";
import {
  formatStatus,
  getStatusBadgeProps,
} from "../../utils/productDisplay";
import {
  buildUpdatePayload,
  productToFormState,
  variantsToFormState,
} from "../../utils/productForm";
import {
  normalizeProductTypes,
  withCurrentProductType,
} from "../../utils/productTypes";
import ProductCategoryPicker from "./ProductCategoryPicker";
import ProductMediaUpload from "./ProductMediaUpload";
import ProductRichTextEditor from "./ProductRichTextEditor";
import ProductVariantSection from "./ProductVariantSection";
import { createNewVariantDraft } from "../../utils/productVariants";

const STATUS_OPTIONS = [
  { value: "active", label: "Active" },
  { value: "draft", label: "Draft" },
  { value: "archived", label: "Archived" },
];

const fieldLabel = { labelAccessibilityVisibility: "exclusive" };

export default function ProductDetail({
  product,
  productTypes = [],
  onBack,
  onSaved,
}) {
  const shopify = useAppBridge();
  const [form, setForm] = useState(() => productToFormState(product));
  const [variants, setVariants] = useState(() =>
    variantsToFormState(product.variants),
  );
  const [saving, setSaving] = useState(false);
  const [saveError, setSaveError] = useState(null);

  useEffect(() => {
    setForm(productToFormState(product));
    setVariants(variantsToFormState(product.variants));
    setSaveError(null);
  }, [product]);

  const updateField = useCallback((field, value) => {
    setForm((prev) => ({ ...prev, [field]: value }));
  }, []);

  const updateVariant = useCallback((index, field, value) => {
    setVariants((prev) =>
      prev.map((variant, i) =>
        i === index ? { ...variant, [field]: value } : variant,
      ),
    );
  }, []);

  const addVariant = useCallback((draft) => {
    setVariants((prev) => [...prev, createNewVariantDraft(draft)]);
  }, []);

  const handleSave = useCallback(async () => {
    setSaving(true);
    setSaveError(null);

    try {
      const token = await shopify.idToken();
      const data = await apiRequest(`/api/product/${product.id}`, {
        method: "PUT",
        token,
        body: buildUpdatePayload(form, variants),
      });
      shopify.toast.show("Product saved");
      onSaved?.(data.data);
    } catch (err) {
      const message = err.message || "Failed to save product";
      setSaveError(message);
      shopify.toast.show(message, { isError: true });
    } finally {
      setSaving(false);
    }
  }, [shopify, form, variants, product.id, onSaved]);

  const pageTitle = form.title.trim() || "Product";
  const statusLabel = formatStatus(form.status);
  const statusBadge = getStatusBadgeProps(form.status);

  useEffect(() => {
    document.title = pageTitle;
  }, [pageTitle]);

  const typeOptions = useMemo(
    () =>
      withCurrentProductType(
        normalizeProductTypes(productTypes, product.availableProductTypes),
        form.productType,
      ),
    [
      productTypes,
      product.availableProductTypes,
      form.productType,
    ],
  );

  return (
    <s-page heading={pageTitle}>
      <s-badge
        slot="accessory"
        size="large"
        tone={statusBadge.tone}
        color={statusBadge.color}
      >
        {statusLabel}
      </s-badge>
      <s-button
        slot="breadcrumb-actions"
        accessibilityLabel="Products"
        href="/products"
        onClick={(event) => {
          event.preventDefault();
          onBack();
        }}
      />
      <s-button
        slot="primary-action"
        variant="primary"
        onClick={handleSave}
        {...(saving ? { loading: true } : {})}
      >
        Save
      </s-button>

      {saveError ? <s-banner tone="critical">{saveError}</s-banner> : null}

      <s-query-container containerName="product-detail">
        <div className="product-detail-layout">
          <div className="product-detail-layout__main">
        <s-stack gap="base">
          <s-section>
            <s-text-field
              label="Title"
              {...fieldLabel}
              value={form.title}
              onInput={(event) =>
                updateField("title", event.currentTarget.value)
              }
            />
          </s-section>

          <s-section heading="Description">
            <ProductRichTextEditor
              key={product.id}
              value={form.bodyHtml}
              onChange={(bodyHtml) => updateField("bodyHtml", bodyHtml)}
            />
          </s-section>

          <s-section heading="Media">
            <ProductMediaUpload
              title={form.title}
              imageUrl={form.imageUrl}
              imageAlt={form.imageAlt}
              onImageChange={({ imageUrl, imageAlt }) =>
                setForm((prev) => ({ ...prev, imageUrl, imageAlt }))
              }
              onError={(message) =>
                shopify.toast.show(message, { isError: true })
              }
            />
          </s-section>

          <s-section heading="Category">
            <ProductCategoryPicker
              value={form.productType}
              extraTypes={typeOptions}
              onChange={(productType) =>
                updateField("productType", productType)
              }
            />
          </s-section>

          <s-section padding="none">
            <s-box padding="base">
              <ProductVariantSection
                variants={variants}
                onVariantChange={updateVariant}
                onAddVariant={addVariant}
              />
            </s-box>
          </s-section>
        </s-stack>
        </div>

        <div className="product-detail-layout__aside">
        <s-stack gap="base">
          <s-section heading="Status">
            <s-select
              label="Status"
              {...fieldLabel}
              value={form.status}
              onChange={(event) =>
                updateField("status", event.currentTarget.value)
              }
            >
              {STATUS_OPTIONS.map((option) => (
                <s-option key={option.value} value={option.value}>
                  {option.label}
                </s-option>
              ))}
            </s-select>
          </s-section>

          <s-section heading="Publishing">
            <s-text>All channels</s-text>
          </s-section>

          <s-section heading="Sales">
            <s-text color="subdued">No recent sales of this product</s-text>
          </s-section>

          <s-section heading="Product organization">
            <s-stack gap="base">
              <s-text-field
                label="Vendor"
                {...fieldLabel}
                value={form.vendor}
                onInput={(event) =>
                  updateField("vendor", event.currentTarget.value)
                }
              />
              <s-text-field
                label="Tags"
                {...fieldLabel}
                value={form.tags}
                onInput={(event) =>
                  updateField("tags", event.currentTarget.value)
                }
              />
            </s-stack>
          </s-section>

          <s-section heading="Theme template">
            <s-select
              label="Theme template"
              {...fieldLabel}
              value={form.templateSuffix || ""}
              onChange={(event) =>
                updateField("templateSuffix", event.currentTarget.value)
              }
            >
              <s-option value="">Default product</s-option>
            </s-select>
          </s-section>
        </s-stack>
        </div>
        </div>
      </s-query-container>
    </s-page>
  );
}
