import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { createPortal } from "react-dom";
import {
  buildCategoryValue,
  getCategoryDisplayLabel,
  getCategoryLevelItems,
  getCategoryTree,
  searchCategories,
} from "../../utils/productCategories";
import "../../styles/ProductCategoryPicker.css";

function isLeafNode(node) {
  return Boolean(node.isLeaf) || !node.children?.length;
}

export default function ProductCategoryPicker({
  value,
  extraTypes = [],
  onChange,
}) {
  const triggerRef = useRef(null);
  const menuRef = useRef(null);
  const tree = useMemo(() => getCategoryTree(), []);
  const [open, setOpen] = useState(false);
  const [search, setSearch] = useState("");
  const [breadcrumb, setBreadcrumb] = useState([]);
  const [menuPosition, setMenuPosition] = useState(null);

  const close = useCallback(() => {
    setOpen(false);
    setSearch("");
    setBreadcrumb([]);
  }, []);

  const updateMenuPosition = useCallback(() => {
    const trigger = triggerRef.current;
    if (!trigger) return;
    const rect = trigger.getBoundingClientRect();
    const viewportPadding = 12;
    const spaceBelow = window.innerHeight - rect.bottom - viewportPadding;
    const maxHeight = Math.min(360, Math.max(200, spaceBelow));
    const maxWidth = window.innerWidth - viewportPadding * 2;
    const width = Math.min(rect.width, maxWidth);
    let left = rect.left;
    if (left + width > window.innerWidth - viewportPadding) {
      left = window.innerWidth - viewportPadding - width;
    }
    if (left < viewportPadding) {
      left = viewportPadding;
    }

    setMenuPosition({
      top: rect.bottom + 4,
      left,
      width,
      maxHeight,
    });
  }, []);

  useEffect(() => {
    if (!open) return undefined;

    updateMenuPosition();

    const onScrollOrResize = () => updateMenuPosition();
    window.addEventListener("resize", onScrollOrResize);
    window.addEventListener("scroll", onScrollOrResize, true);

    const onPointerDown = (event) => {
      const target = event.target;
      if (triggerRef.current?.contains(target)) return;
      if (menuRef.current?.contains(target)) return;
      close();
    };

    const timer = window.setTimeout(() => {
      document.addEventListener("mousedown", onPointerDown);
    }, 0);

    return () => {
      window.clearTimeout(timer);
      document.removeEventListener("mousedown", onPointerDown);
      window.removeEventListener("resize", onScrollOrResize);
      window.removeEventListener("scroll", onScrollOrResize, true);
    };
  }, [open, close, updateMenuPosition]);

  const isSearching = search.trim().length > 0;

  const listItems = useMemo(() => {
    if (isSearching) {
      return searchCategories(tree, search, extraTypes);
    }
    return getCategoryLevelItems(tree, breadcrumb);
  }, [tree, search, extraTypes, breadcrumb, isSearching]);

  const handleItemClick = (item) => {
    if (isSearching || isLeafNode(item)) {
      onChange(
        isSearching ? item.name : buildCategoryValue(breadcrumb, item.name),
      );
      close();
      return;
    }

    setBreadcrumb((prev) => [...prev, { id: item.id, name: item.name }]);
    setSearch("");
  };

  const handleBack = () => {
    setBreadcrumb((prev) => prev.slice(0, -1));
    setSearch("");
  };

  const hasValue = Boolean(value?.trim());
  const label = hasValue
    ? getCategoryDisplayLabel(value)
    : "Choose a product category";

  const menu =
    open && menuPosition
      ? createPortal(
          <div
            ref={menuRef}
            className="category-picker__menu category-picker__menu--portal"
            style={{
              top: menuPosition.top,
              left: menuPosition.left,
              width: menuPosition.width,
              maxHeight: menuPosition.maxHeight,
            }}
            role="listbox"
          >
            <div className="category-picker__search">
              <input
                type="text"
                className="category-picker__search-input"
                placeholder="Search categories"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                autoFocus
              />
            </div>

            <div className="category-picker__list">
              {breadcrumb.length > 0 && !isSearching ? (
                <button
                  type="button"
                  className="category-picker__back"
                  onClick={handleBack}
                >
                  ← Back
                </button>
              ) : null}

              {listItems.map((item) => (
                <button
                  key={item.id}
                  type="button"
                  className="category-picker__item"
                  onClick={() => handleItemClick(item)}
                >
                  <span>{item.name}</span>
                  {!isSearching && !isLeafNode(item) ? (
                    <span className="category-picker__item-chevron">›</span>
                  ) : null}
                </button>
              ))}

              {listItems.length === 0 ? (
                <p className="category-picker__empty">No categories found</p>
              ) : null}
            </div>
          </div>,
          document.body,
        )
      : null;

  return (
    <div className="category-picker">
      <button
        ref={triggerRef}
        type="button"
        className={`category-picker__trigger${open ? " is-open" : ""}`}
        aria-expanded={open}
        aria-haspopup="listbox"
        onClick={() => {
          setOpen((wasOpen) => {
            if (!wasOpen) updateMenuPosition();
            return !wasOpen;
          });
        }}
      >
        <span
          className={hasValue ? undefined : "category-picker__placeholder"}
        >
          {label}
        </span>
        <span className="category-picker__chevron">▾</span>
      </button>

      <p className="category-picker__details">
        Determines tax rates and improves search, filters, and cross-channel
        sales.
      </p>

      {menu}
    </div>
  );
}
