import { useMemo, useState } from "react";
import { useAppBridge } from "@shopify/app-bridge-react";
import {
  getTotalInventory,
  getVariantDisplayName,
  getVariantRowKey,
  findVariantIndex,
} from "../../utils/productVariants";
import { getInputEventValue } from "../../utils/fieldEvent";
import "../../styles/ProductVariants.css";

const fieldLabel = { labelAccessibilityVisibility: "exclusive" };

const emptyDraft = () => ({
  name: "",
  price: "",
  inventoryQuantity: "0",
});

export default function ProductVariantSection({
  variants,
  onVariantChange,
  onAddVariant,
}) {
  const shopify = useAppBridge();
  const [showAddForm, setShowAddForm] = useState(false);
  const [draft, setDraft] = useState(emptyDraft);

  const totalInventory = useMemo(
    () => getTotalInventory(variants),
    [variants],
  );

  const openAddForm = () => {
    setDraft(emptyDraft());
    setShowAddForm(true);
  };

  const cancelAddForm = () => {
    setShowAddForm(false);
    setDraft(emptyDraft());
  };

  const submitAddForm = () => {
    const name = String(draft.name ?? "").trim();
    if (!name) {
      shopify.toast.show("Enter a variant name", { isError: true });
      return;
    }

    onAddVariant({
      name,
      price: String(draft.price ?? "").trim() || "0.00",
      inventoryQuantity: String(draft.inventoryQuantity ?? "").trim() || "0",
    });

    setShowAddForm(false);
    setDraft(emptyDraft());
    shopify.toast.show("Variant added — click Save to publish");
  };

  return (
    <div className="product-variants">
      <div className="product-variants__header">
        <s-text type="strong">Variants</s-text>
        {!showAddForm ? (
          <s-button variant="tertiary" onClick={openAddForm}>
            + Add variant
          </s-button>
        ) : null}
      </div>

      {showAddForm ? (
        <div className="product-variants__add-form">
          <s-text-field
            label="Variant name"
            placeholder="e.g. Khaki, Large"
            value={draft.name}
            onInput={(event) => {
              const value = getInputEventValue(event);
              setDraft((prev) => ({ ...prev, name: value }));
            }}
          />
          <s-money-field
            label="Price"
            {...fieldLabel}
            value={draft.price}
            onInput={(event) => {
              const value = getInputEventValue(event);
              setDraft((prev) => ({ ...prev, price: value }));
            }}
          />
          <s-text-field
            label="Available"
            {...fieldLabel}
            value={draft.inventoryQuantity}
            onInput={(event) => {
              const value = getInputEventValue(event);
              setDraft((prev) => ({ ...prev, inventoryQuantity: value }));
            }}
          />
          <s-stack direction="inline" gap="small">
            <s-button variant="primary" onClick={submitAddForm}>
              Add variant
            </s-button>
            <s-button variant="tertiary" onClick={cancelAddForm}>
              Cancel
            </s-button>
          </s-stack>
        </div>
      ) : null}

      {variants.length === 0 && !showAddForm ? (
        <s-text color="subdued">No variants yet.</s-text>
      ) : null}

      {variants.length > 0 ? (
        <>
          <s-query-container containerName="product-variants">
            <div className="products-table-host">
              <s-stack>
                <s-table>
                  <s-table-header-row>
                    <s-table-header listSlot="primary">Variant</s-table-header>
                    <s-table-header format="numeric">Price</s-table-header>
                    <s-table-header format="numeric">Available</s-table-header>
                  </s-table-header-row>
                  <s-table-body>
                    {variants.map((variant) => {
                      const index = findVariantIndex(variants, variant);
                      const rowKey = getVariantRowKey(variant);
                      const displayName = getVariantDisplayName(variant);

                      return (
                        <s-table-row key={rowKey}>
                          <s-table-cell>
                            <s-text type="strong">{displayName}</s-text>
                          </s-table-cell>
                          <s-table-cell>
                            <s-money-field
                              label="Price"
                              {...fieldLabel}
                              value={variant.price}
                              onInput={(event) =>
                                onVariantChange(
                                  index,
                                  "price",
                                  getInputEventValue(event),
                                )
                              }
                            />
                          </s-table-cell>
                          <s-table-cell>
                            <s-text-field
                              label="Available"
                              {...fieldLabel}
                              value={variant.inventoryQuantity}
                              onInput={(event) =>
                                onVariantChange(
                                  index,
                                  "inventoryQuantity",
                                  getInputEventValue(event),
                                )
                              }
                            />
                          </s-table-cell>
                        </s-table-row>
                      );
                    })}
                  </s-table-body>
                </s-table>
              </s-stack>
            </div>
          </s-query-container>

          <p className="product-variants__footer">
            Total inventory: {totalInventory} available
          </p>
        </>
      ) : null}
    </div>
  );
}
